  $('Configure LLM Provider').first().json.llm_config || {
    llm_provider: 'openai',
    llm_url: 'https://api.openai.com/v1/chat/completions',
    llm_model: 'gpt-4o-mini',
    llm_supports_structured_output: true
  };

// Define JSON schema for structured output
const candidateSchema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    full_name: { type: ['string', 'null'] },
    city: { type: ['string', 'null'] },
    desired_position: { type: ['string', 'null'] },
    experience_years: { type: ['number', 'null'] },
    skills: { type: 'array', items: { type: 'string' } },
    salary_expectation: { type: ['number', 'null'] },
    email: { type: ['string', 'null'] },
    phone: { type: ['string', 'null'] },
    summary: { type: ['string', 'null'] }
  },
  required: [
    'full_name',
    'city',
    'desired_position',
    'experience_years',
    'skills',
    'salary_expectation',
    'email',
    'phone',
    'summary'
  ]
};

// Build request body
const openai_body = {
  model: llmConfig.llm_model,
  temperature: 0,
  messages: [
    {
      role: 'system',
      content: 'Ты — HR-ассистент для извлечения структурированных данных из резюме. Извлекай только явно присутствующие данные. Не выдумывай отсутствующие сведения.'
    },
    {
      role: 'user',
      content: 'Извлеки данные кандидата из текста резюме:\n\n' + text
    }
  ]
};

// Add response_format only if provider supports it
if (llmConfig.llm_supports_structured_output) {
  openai_body.response_format = {
    type: 'json_schema',
    json_schema: {
      name: 'candidate_profile',
      strict: true,
      schema: candidateSchema
    }
  };
}

return [{
  json: {
    ...$json,
    llm_config: llmConfig,
    openai_body: openai_body
  }
}];

function extractRaw(itemJson) {
  return itemJson.choices?.[0]?.message?.content || '';
}

function parseJson(raw) {
  if (!raw || typeof raw !== 'string') {
    return null;
  }

  try {
    return JSON.parse(raw);
  } catch (e) {
    return null;
  }
}

const ctx = $('Prepare OpenAI Body: Extract candidate JSON').first().json;
const raw = extractRaw($json);
const candidate = parseJson(raw);

const requiredFields = [
  'full_name',
  'city',
  'desired_position',
  'experience_years',
  'skills',
  'salary_expectation',
  'email',
  'phone',
  'summary'
];

const hasObject = candidate && typeof candidate === 'object' && !Array.isArray(candidate);

const hasAllFields = hasObject && requiredFields.every(field =>
  Object.prototype.hasOwnProperty.call(candidate, field)
);

const validTypes =
  hasObject &&
  Array.isArray(candidate.skills) &&
  (candidate.experience_years === null || typeof candidate.experience_years === 'number') &&
  (candidate.salary_expectation === null || typeof candidate.salary_expectation === 'number');

const isValid = Boolean(hasObject && hasAllFields && validTypes);

return [
  {
    json: {
      ...ctx,
      llm_provider: ctx.llm_config?.llm_provider || 'openai',
      llm_raw_candidate_response: raw,
      candidate: isValid ? candidate : null,
      candidate_json_valid: isValid,
      candidate_json_error: isValid ? null : 'Invalid candidate JSON structure'
    }
  }
];

const resumeText = String(
