function extractRaw(itemJson) {
  return itemJson.choices?.[0]?.message?.content
    || itemJson.message?.content
    || itemJson.text
    || itemJson.output
    || '';
}

function parseJson(raw) {
  if (!raw || typeof raw !== 'string') {
    return null;
  }

  let cleaned = raw.trim();

  cleaned = cleaned
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return null;

    try {
      return JSON.parse(match[0]);
    } catch (e2) {
      return null;
    }
  }
}

const ctx = $('Parse OpenAI Candidate JSON').first().json;

const raw = extractRaw($json);
const candidate = parseJson(raw);

const requiredFields = [
  'full_name',
  'city',
  'desired_position',
  'experience_years',
  'skills',
  'salary_expectation',
  'email',
  'phone',
  'summary'
];

const hasObject =
  candidate &&
  typeof candidate === 'object' &&
  !Array.isArray(candidate);

const hasAllFields =
  hasObject &&
  requiredFields.every(field =>
    Object.prototype.hasOwnProperty.call(candidate, field)
  );

const validTypes =
  hasObject &&
  (candidate.skills === null || Array.isArray(candidate.skills)) &&
  (candidate.experience_years === null || typeof candidate.experience_years === 'number') &&
  (candidate.salary_expectation === null || typeof candidate.salary_expectation === 'number');

const isValid = Boolean(hasObject && hasAllFields && validTypes);

return [
  {
    json: {
      ...ctx,
      llm_provider: ctx.llm_config?.llm_provider || 'openai',
      llm_raw_candidate_repair_response: raw,
      candidate: isValid ? candidate : null,
      candidate_json_valid: isValid,
      candidate_json_error: isValid
        ? null
        : 'Invalid candidate JSON after repair'
    }
  }
];

const c = $json.candidate || {};

const hasName = Boolean(c.full_name && c.full_name.trim());
const hasPosition = Boolean(c.desired_position && c.desired_position.trim());
const hasContacts = Boolean(
  (c.email && c.email.trim()) ||
  (c.phone && c.phone.trim())
);
const hasSkills = Array.isArray(c.skills) && c.skills.length >= 2;

const isMeaningful =
  hasName ||
  hasPosition ||
  hasContacts ||
  hasSkills;

return [{
  json: {
    ...$json,
    candidate_meaningful: isMeaningful
  }
}];

return [{
  json: {
    ...$json,
    error_stage: 'processing',
    error_type: 'candidate_json_error',
    error_message: $json.candidate_json_error || 'Candidate JSON parsing failed',
    error_recoverable: true,
    response_channel: 'telegram',
    response_recipient: $json.chat_id ? String($json.chat_id) : null,
    response_message_type: 'error',
    response_subject: null,
    response_body:
`⚠️ Не удалось корректно разобрать данные резюме

Пожалуйста, попробуйте отправить резюме ещё раз или используйте другой формат: текст, PDF/DOCX, фото или голос.`
  }
}];

const ctx = $json;
const candidate = ctx.candidate || {};

const email = (candidate.email || '').toLowerCase().trim();

let phone = (candidate.phone || '').trim();
phone = phone.replace(/[^\d+]/g, '');

if (phone.startsWith('8') && phone.length === 11) {
  phone = '+7' + phone.slice(1);
}

return [{
  json: {
    ...ctx,
    candidate: {
      ...candidate,
      email_normalized: email || null,
      phone_normalized: phone || null
    }
  }
}];

const ctx = $('Normalize candidate contacts').first().json;

const dedupResult = $json.dedup_result || 'not_found';
const existingCandidateId = $json.candidate_id || null;

return [{
  json: {
    ...ctx,
    existing_candidate_id: existingCandidateId,
    is_duplicate_candidate: Boolean(existingCandidateId),
    dedup_result: dedupResult,
    matched_candidates_count: Number($json.matched_candidates_count || 0),
    email_candidate_id: $json.email_candidate_id || null,
    phone_candidate_id: $json.phone_candidate_id || null,
    contact_conflict: dedupResult === 'contact_conflict'
  }
}];

return [{
  json: {
    ...$json,
    candidate_id: $json.existing_candidate_id,
    candidate_dedup_status: 'existing'
  }
}];

const ctx = $('Normalize candidate contacts').first().json;

return [{
  json: {
    ...ctx,
    candidate_id: $json.id,
    candidate_dedup_status: 'new'
  }
}];

const ctx = $('Build context after candidates').first().json;

return [{
  json: {
    ...ctx,
    contacts_saved: true
  }
}];

const candidate = $json.candidate || {};
const vacancy = $json.vacancy || {};

// Get LLM provider configuration
const llmConfig =
  $('Configure LLM Provider').first().json.llm_config || {
    llm_provider: 'openai',
    llm_url: 'https://api.openai.com/v1/chat/completions',
    llm_model: 'gpt-4o-mini',
    llm_supports_structured_output: true
  };

// Define JSON schema
const matchSchema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    vacancy_id: { type: ['string', 'null'] },
    title: { type: ['string', 'null'] },
    role_score: { type: 'number' },
    skills_score: { type: 'number' },
    experience_score: { type: 'number' },
    conditions_score: { type: 'number' },
    score: { type: 'number' },
    decision: {
      type: 'string',
      enum: ['match', 'no_match']
    },
    reason: { type: 'string' }
  },
  required: [
    'vacancy_id',
    'title',
    'role_score',
    'skills_score',
    'experience_score',
    'conditions_score',
    'score',
    'decision',
    'reason'
  ]
};

// Build request body
const openai_body = {
  model: llmConfig.llm_model,
  temperature: 0,
  messages: [
    {
      role: 'system',
      content: `Ты HR matching assistant.

Сравни кандидата и вакансию по критериям:

1. Должность / роль — 30 баллов
2. Навыки — 35 баллов
3. Опыт — 20 баллов
4. Город / формат / зарплатные ожидания — 15 баллов

Итоговый score должен быть от 0 до 100.

Правила:
- score >= 60 → decision = "match"
- score < 60 → decision = "no_match"
- не выдумывай навыки и опыт
- если данных недостаточно, снижай score
- reason должен кратко объяснять, почему выставлен такой score

Верни строго JSON по схеме.`
    },
    {
      role: 'user',
      content:
        'Кандидат:\n' +
        JSON.stringify(candidate, null, 2) +
        '\n\nВакансия:\n' +
        JSON.stringify(vacancy, null, 2)
    }
  ]
};

// Add response_format only if provider supports it
if (llmConfig.llm_supports_structured_output) {
  openai_body.response_format = {
    type: 'json_schema',
    json_schema: {
      name: 'vacancy_match_result',
      strict: true,
      schema: matchSchema
    }
  };
}

return {
  json: {
    ...$json,
    llm_config: llmConfig,
    openai_body: openai_body
  }
};

function extractRaw(itemJson) {
  return itemJson.choices?.[0]?.message?.content || '';
}

function parseJson(raw, fallback) {
  if (!raw || typeof raw !== 'string') {
    return fallback;
  }

  let cleaned = raw.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return fallback;

    try {
      return JSON.parse(match[0]);
    } catch (e2) {
      return fallback;
    }
  }
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, Number(value || 0)));
}

const sourceItems = $('Prepare OpenAI Body: Match candidate vacancy').all();

return items.map((item, index) => {
  const source = sourceItems[index]?.json || {};
  const raw = extractRaw(item.json);

  const fallback = {
    vacancy_id: source.vacancy?.id || null,
    title: source.vacancy?.title || '',
    role_score: 0,
    skills_score: 0,
    experience_score: 0,
    conditions_score: 0,
    score: 0,
    decision: 'no_match',
    reason: 'Не удалось разобрать ответ модели'
  };

  const parsed = parseJson(raw, fallback);

  const roleScore = clamp(parsed.role_score, 0, 30);
  const skillsScore = clamp(parsed.skills_score, 0, 35);
  const experienceScore = clamp(parsed.experience_score, 0, 20);
  const conditionsScore = clamp(parsed.conditions_score, 0, 15);

  const calculatedScore =
    roleScore +
    skillsScore +
    experienceScore +
    conditionsScore;

  const modelScore = clamp(parsed.score, 0, 100);
  const score = calculatedScore > 0 ? calculatedScore : modelScore;

  return {
    json: {
      ...source,
      llm_provider: source.llm_config?.llm_provider || 'openai',
      llm_raw_match_response: raw,
      match_result: {
        vacancy_id: parsed.vacancy_id || source.vacancy?.id || null,
        title: parsed.title || source.vacancy?.title || '',
        role_score: roleScore,
        skills_score: skillsScore,
        experience_score: experienceScore,
        conditions_score: conditionsScore,
        score,
        decision: score >= 60 ? 'match' : 'no_match',
        reason: parsed.reason || ''
      }
    }
  };
});

const parsedItems = $('Parse match JSON').all();

return items.map((item, index) => {
  const source = parsedItems[index].json;

  return {
    json: {
      ...source,
      match_db: item.json
    }
  };
});

const all = items.map(i => i.json);

all.sort((a, b) => {
  const scoreA = Number(a.match_db?.score || a.match_result?.score || 0);
  const scoreB = Number(b.match_db?.score || b.match_result?.score || 0);
  return scoreB - scoreA;
});

const best = all[0] || {};
const bestScore = Number(best.match_db?.score || best.match_result?.score || 0);

const hasMatch = bestScore >= 60;

const criteria = best.match_result || {};

return [{
  json: {
    ...best,
    best_match: {
      match_id: best.match_db?.id || null,
      vacancy_id: best.match_db?.vacancy_id || best.vacancy?.id || null,
      title: best.match_result?.title || best.vacancy?.title || '',
      score: bestScore,
      decision: hasMatch ? 'match' : 'no_match',
      reason: best.match_result?.reason || '',
      criteria: {
        role_score: Number(criteria.role_score || 0),
        skills_score: Number(criteria.skills_score || 0),
        experience_score: Number(criteria.experience_score || 0),
        conditions_score: Number(criteria.conditions_score || 0)
      }
    },
    has_match: hasMatch
  }
}];

const ctx = $('Select best match').first().json;

return [{
  json: {
    ...ctx,
    final_decision_id: $json.id
  }
}];;

const sourceCtx = $('Prepare OpenAI Body: Extract candidate JSON').first().json || {};

const match = $json.best_match || {};
const c = match.criteria || {};

const chatId =
  $json.chat_id ||
  sourceCtx.chat_id ||
  null;

if (!chatId) {
  throw new Error('chat_id is missing before final Telegram response');
}

const title = match.title || 'Подходящая вакансия';
const score = Number(match.score || 0);

let body;

if ($json.has_match) {
  body =
`💼 ${title}

📊 Совпадение: ${score}/100

Детализация:
• роль: ${c.role_score || 0}/30
• навыки: ${c.skills_score || 0}/35
• опыт: ${c.experience_score || 0}/20
• условия: ${c.conditions_score || 0}/15

📝 ${match.reason || '—'}

Вы можете откликнуться на вакансию или отправить другое резюме.`;
} else {
  body =
`ℹ️ Результат анализа

Подходящей вакансии пока нет.

📊 Лучшее совпадение: ${score}/100

Детализация:
• роль: ${c.role_score || 0}/30
• навыки: ${c.skills_score || 0}/35
• опыт: ${c.experience_score || 0}/20
• условия: ${c.conditions_score || 0}/15

📝 ${match.reason || '—'}

Мы сохраним информацию и вернёмся при появлении релевантной позиции.`;
}

const buttons = $json.has_match
  ? [
      [
        {
          text: '✅ Откликнуться',
          callback_data: 'apply'
        }
      ],
      [
        {
          text: '🔄 Другая вакансия',
          callback_data: 'next'
        }
      ],
      [
        {
          text: '🎬 Сгенерировать видео',
          callback_data: 'video'
        }
      ],
      [
        {
          text: '📄 Отправить другое резюме',
          callback_data: 'restart'
        }
      ]
    ]
  : [
      [
        {
          text: '📄 Отправить другое резюме',
          callback_data: 'restart'
        }
      ]
    ];

return [{
  json: {
    ...$json,

    chat_id: String(chatId),

    response_channel: 'telegram',
    response_recipient: String(chatId),
    response_message_type: $json.has_match ? 'match_card' : 'no_match',
    response_subject: null,
    response_body: body,

    telegram_reply_markup: {
      inline_keyboard: buttons
    }
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'processing',
    response_body:
`🔍 Анализирую резюме

📊 Сравниваю кандидата с открытыми вакансиями...`
  }
}];

