// Configure LLM Provider
// Provider selection: openai (default) | runpod
// Set via environment variable LLM_PROVIDER

const provider = 'runpod';

const configs = {
  openai: {
    llm_provider: 'openai',
    llm_url: 'https://api.openai.com/v1/chat/completions',
